{"code": "import json

# Load Europe article metadata
file_path = locals()['var_functions.query_db:6']
with open(file_path, 'r') as f:
    europe_articles = json.load(f)

# Build year mapping for each article
articles_by_year = {}
for article in europe_articles:
    year = int(article['publication_date'][:4])
    if year not in articles_by_year:
        articles_by_year[year] = []
    articles_by_year[year].append(int(article['article_id']))

# Sort by year
sorted_years = dict(sorted(articles_by_year.items()))

print('__RESULT__:')
print(json.dumps({
    'year_range': '2010-2020',
    'articles_per_year': {year: len(ids) for year, ids in sorted_years.items()},
    'total_articles': sum(len(ids) for ids in sorted_years.values())
}))"}

